mapper.select:
SELECT DISTINCT r.room_id as roomId, r.room_number as roomNumber, b.building_name as building, f.floor_name as floor, rt.type_name as roomType, r.status, rs.status_name as statusName, rs.status_color as statusColor, CASE WHEN rt.price IS NOT NULL THEN rt.price ELSE NULL END as price, rt.max_guests AS capacity, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'checked_in') THEN COALESCE(o.adults + o.children, 0) ELSE 0 END as currentGuests, o.order_id as orderId, o.order_no as orderNo, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.guest_name ELSE NULL END as guestName, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.guest_phone ELSE NULL END as guestPhone, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.id_card ELSE NULL END as idCard, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.check_in_date ELSE NULL END as checkInTime, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.check_out_date ELSE NULL END as checkOutTime, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.nights ELSE NULL END as nights, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.total_amount ELSE NULL END as totalAmount, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.order_status ELSE NULL END as orderStatus, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.payment_status ELSE NULL END as paymentStatus, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.payment_method ELSE NULL END as paymentMethod, CASE WHEN r.status IN ('occupied_clean', 'occupied_dirty', 'occupied', 'checked_in') THEN o.book_channel ELSE NULL END as bookChannel, b.building_id, f.floor_number FROM room r LEFT JOIN building b ON r.building_id = b.building_id LEFT JOIN floor f ON r.floor_id = f.floor_id LEFT JOIN room_type rt ON r.type_id = rt.type_id LEFT JOIN room_status rs ON r.status = rs.status_code LEFT JOIN orders o ON r.room_id = o.room_id AND o.order_status IN ('checked_in', 'reserved')
AND ( r.room_number LIKE CONCAT('%', #{query.searchText}, '%') OR o.order_no LIKE CONCAT('%', #{query.searchText}, '%') OR o.guest_phone LIKE CONCAT('%', #{query.searchText}, '%') )
AND b.building_id = #{query.building}
AND f.floor_id = #{query.floor}
AND rt.type_id = #{query.roomType}
AND
FIND_IN_SET(#{feature}, r.features) > 0
AND ( r.status = 'empty_clean' OR r.status = 'free' OR r.status = 'available' OR r.status = 'empty_dirty' OR r.status = 'dirty' OR r.status = 'pending_cleaning' OR r.status = 'maintenance' OR r.status = 'locked' OR r.status = 'self_use' OR EXISTS (SELECT 1 FROM orders o2 WHERE o2.room_id = r.room_id AND o2.order_status = 'reserved') OR r.status = 'occupied_clean' OR r.status = 'occupied_dirty' OR r.status = 'occupied' OR r.status = 'checked_in' OR EXISTS (SELECT 1 FROM orders o2 WHERE o2.room_id = r.room_id AND o2.order_status = 'checked_in' AND o2.check_out_date = CURDATE()) OR 1=0 )
AND o.book_channel = #{query.channel}
ORDER BY b.building_id, f.floor_number, r.room_number LIMIT #{offset}, #{limit}

SELECT COUNT(DISTINCT r.room_id) FROM room r LEFT JOIN building b ON r.building_id = b.building_id LEFT JOIN floor f ON r.floor_id = f.floor_id LEFT JOIN room_type rt ON r.type_id = rt.type_id LEFT JOIN room_status rs ON r.status = rs.status_code LEFT JOIN orders o ON r.room_id = o.room_id AND o.order_status IN ('checked_in', 'reserved')
AND ( r.room_number LIKE CONCAT('%', #{query.searchText}, '%') OR o.order_no LIKE CONCAT('%', #{query.searchText}, '%') OR o.guest_phone LIKE CONCAT('%', #{query.searchText}, '%') )
AND b.building_id = #{query.building}
AND f.floor_id = #{query.floor}
AND rt.type_id = #{query.roomType}
AND
FIND_IN_SET(#{feature}, r.features) > 0
AND ( r.status = 'empty_clean' OR r.status = 'free' OR r.status = 'available' OR r.status = 'empty_dirty' OR r.status = 'dirty' OR r.status = 'pending_cleaning' OR r.status = 'maintenance' OR r.status = 'locked' OR r.status = 'self_use' OR EXISTS (SELECT 1 FROM orders o2 WHERE o2.room_id = r.room_id AND o2.order_status = 'reserved') OR r.status = 'occupied_clean' OR r.status = 'occupied_dirty' OR r.status = 'occupied' OR r.status = 'checked_in' OR EXISTS (SELECT 1 FROM orders o2 WHERE o2.room_id = r.room_id AND o2.order_status = 'checked_in' AND o2.check_out_date = CURDATE()) OR 1=0 )
AND o.book_channel = #{query.channel}

mapper.update:
UPDATE orders SET 
order_status = 'checked_out'
, remarks = #{remark}
WHERE order_id = #{orderId}
